INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1486, 194773, 1, 311, '永远的未完成', '在苏格兰的笛声里面印度式的颓废让弄蛇人被蛇捆成一团,你可知道现在的我很可怜？心情苦涩,失眠引起的忧郁血丝蔓延。我闷得受不了,什么也做不好。我开始晕眩。
<br>就在一瞬间，我们两个眼前一道光带我们到了另外一个世界。这里的姑娘眉中间都有一个红点，头纱遮住脸。好像每个人都有特别的气味,闻到了才发现那是咖喱在作祟。恒河水、菩提树叶、古老的情节，时间在倒回。我们两穿着布纱，听着梵乐，幻觉里奇怪的语言催着我快快起舞。时空换换换换换，时空转转转转转．．．我的爱从古代和你回来，你回到过去，我经历了悲伤。好神奇，又回到了这里。
<br>　　回到了这里，又站在你家的门口。你终于开口向我诉说她有的温柔，虽然你还握着我的手，但我清楚的知道我已不在你的心中。我真的懂，你不是喜新厌旧只是我没有陪在你身边当你寂寞的时候。我知道你要的是你的自由，当你对我说爱情没有对错，我就没有再问什么。因为我懂得你最喜欢懂事的我。你很难开口，我知道你要说什么，当你说觉得我很难过，我却不知道是应该微笑还是沉默。就让我走吧，让我开始享受自由，回忆很多你的影子充满我的生活，我并不懦弱你应该比谁都懂。我一直在用我自己的角度看这个世界的庸庸碌碌，所得到的感触一定超乎你想象的程度，就让我写下爱的休止符，希望也得到你的祝福。
<br>　　今天星期一，离开了你，我没有行李，找不到表情，可是并不恨你。因为我不爱推理的游戏。我没有再绕路为了见你。当然还是会有点伤心，伤心总是让你不想爱自己，可是那也没有办法，也只好暂时不爱你，拉开距离，等到有一天忽然想起你了，再翻出旧的日记从新写起星期一天气晴，我离开了你。
<br>　　离开你以后，我决定换一个地方。却忽然发现自己一直站在梦想的路上，我心里一直相信若是梦想还在，就一定可以实现，虽然是如此靠近的遥远。但是接下来我只要记得起点，去迎接，不后退。接下来的可好可坏，只要有信念陪在的每一天。就算我偶尔感觉累了，但信念仍推着我向前。我忍不住就对天空大叫了句：All I wan do I do it for you.
<br>　　我把自己在一个小城市里安定了下来，找了份工作安静的活着。每天我总要绕路回家，有些事情也渐渐的复杂，拐个弯说话是不是代表着必须长大了？我要确定自己，可好像是来不及。心情在变化，找不到一个人要我的答案。现在的我是否有些不同？努力的工作却也努力的犯错。二十五岁的我开始学着大人应该有的动作，翻来覆去。现实让我退缩梦想已经不够，想法渐渐成熟，可是下个脚步我要怎么做？都不能有点懒散，虽然私底下常常让脑袋在放假。新鲜的念头冲击着我，我看只有快点张开双臂去飞翔挑战一切，飞越更多的空间才能体验。真想让时间停住，享受这一分钟我深深的体会，这个世界的规则有点难懂，曾努力却不一定有收获，那只能怪未知的事情太多．．．．．．
<br>　　穿过人群，拥挤的夜不算熟悉的地方，陌生的眼光，音乐却是那样的继续。看着行人跟我逆向，从道路的两旁转进小巷一栋被废弃的工厂，在墙上我涂鸦小时候单纯美好的愿望，穿白纱当新娘。我又绕到广场，闹市区的电视墙在唱歌，歌唱的内容跟我现在的心情很像。我一个人站在红绿灯前，看天上，看天上。我又绕到街上，晃一晃感觉花店的落地窗很漂亮．．．．哎呀，怎么会让我也变得一样冷漠眼光？还在为了生活而慌张。究竟是什么力量竟然能让梦想被遗忘？现实实在太让人受伤，真心却换来悲剧的收场。真的想要解放，面对现实的失望却有太多的假装。带我离开这个地方！我大叫。冷静下来，其实这个虚伪的世界就是这个模样，不要太去在意别人什么眼光。受了伤，再沮丧。我也要有自己的向往。但是当我察觉到我眼底的光芒时，才发现我还是怀抱希望、理想痛哭一场，在那没有人的地方走自己的方向。我向前冲，我还再跟人群逆向，在街上从道路的两旁转进小巷。在一栋废弃的工厂墙上涂鸦我的种种不满。Hey　挑战一切！
<br>我决定不再愁眉苦脸，因为用意大利式的方法浪费时间，都让我感受不到美好事物的瞬间。我的青春像那凡尔赛的玫瑰又爽又多刺又鲜艳，我想在威廉古堡的旁边有一个幸福的结局。不久，王子出现了。我一直相信，给我誓言不如陪我消遣；给我王子倒不如给我王子面，他就是给我王子面的王子。王子和公主一起吃着王子面，我说让我们闭上眼睛让时间倒带。我的小时候――拖着鼻涕的童年，我吃着王子面。快乐的简单，幸福其实不远。手上拿着五块来到港口老板手中接下期待已久的滋味。其实这就是有关的人生道理，现在却只剩下小节。Wowo还是让我们继续close window吧～
<br>　　王子却说：Hey Jude找一首悲伤的歌把它唱得更快乐吧！记得把它唱入你的心田。世界就会开始好转。Hey Jude。别害怕，你天生就是勇于克服，恐惧当你将它深埋于心底的那一刻，世界就会开始好转。每当感受疼痛的滋味Hey Jude，要忍耐。别把世界的重担都往肩上扛，你要知道那是个愚蠢的人，总是装作不在乎把自己的世界弄得很残酷。
<br>　　我听了王子的话以后，看着镜子中的自己，不禁纳闷。这个怪胎是谁啊？为什么这个世界要欺骗？为什么我又要去幻想相信？我找到我的弱点了，我仍然想当个有原则的人，这些原则就像小孩子一样的纯真，像圣人一样慷慨的给予，像天使一样的去感受。
<br>　　我终于明白了，生活在世界，未完成是个期待。永远做不完。想平凡，想特别，我想一切就像绕个路，拐个弯。要负责任，告诉自己别偷懒。这一切都在逼我成长。这么说来自己的期待，有时候都说不出来到底未完成什么？我会考虑我的直觉的，现在开始感觉不错――活在这个世界上。或许未完成就是个期待，永远做不成。', '在苏格兰的笛声里面印度式的颓废让弄蛇人被蛇捆成一团,你可知道现在的我很可怜？心情苦涩,失眠引起的忧郁血丝蔓延。我闷得受不了,什么也做不好。我开始晕眩。

